import React from 'react';
const WordCloud = () => {
  return (
    <div style={{background:'white',padding:'1.5rem',borderRadius:'1rem',boxShadow:'0 4px 6px rgba(0,0,0,0.1)',marginTop:'1.5rem'}}>
      <h3 style={{color:'#0D47A1',marginBottom:'1rem',textAlign:'center'}}>☁️ Nuage de Mots Clés</h3>
      <p style={{color:'#666',textAlign:'center'}}>Chargement du nuage de mots...</p>
    </div>
  );
};
export default WordCloud;
